import {BrowserRouter, Switch, Route} from 'react-router-dom';
import { About } from '../pages/about';
import { Home } from '../pages/home';

export function Router(){
  return (
    <BrowserRouter>
      <Switch>
        <Route path="/" exact component={Home}/>
        <Route path="/about" component={About}/>
      </Switch>
    </BrowserRouter>
  )
}